src/component/Menu.js
import React from 'react';

const menuContainerStyle = {
    position: 'relative',
    width: '300px',
    padding: '14px',
    fontFamily: 'Microsoft JhengHei',
    paddingBottom: '7px',
    backgroundColor: 'white',
    border: '1px solid #E5E5E5',
};

const menuTitleStyle = {
    marginBottom: '7px',
    fontWeight: 'bold',
    color: '#00a0e9',
    cursor: 'pointer',
};

const menuBtnStyle = {
    position: 'absolute',
    right: '7px',
    top: '33px',
    backgroundColor: 'transparent',
    border: 'none',
    color: '#00a0e9',
    outline: 'none',
};

function Menu(props) {
    const [isOpen, setIsOpen] = useState(false);
    return (
        <div style={menuContainerStyle}>
            <p style={menuTitleStyle}>{props.title}</p>
            <button
                style={menuBtnStyle}
                onClick={() => {
                    setIsOpen(!isOpen);
                }}
            >
                {isOpen ? '^' : 'V'}
            </button>
            {isOpen && <ul>{props.children}</ul>}
        </div>
    );
}
想了很久，你得出了這個結論:所以就是把 Menu 的 setIsOpen 傳到 MenuPage 再傳進去 MenuItem 裡面嘛!於是你又開始思考要怎麼把 Menu 的 setIsOpen 傳到父元件 MenuPage 中...
難道沒有更好的做法嗎?
這個「把 Menu 的 setIsOpen 傳到 MenuPage 再傳進去 MenuItem 裡面」的作法雖然的確可行，但是可讀性超差，而且有太多要考量的事情。當專案一大起來，我們更不可能這樣做，不然程式碼就全部都會被沒有用的傳遞函式和 props 給占滿了。「有沒有一個全局的 state 和 setState 可以讓所有的元件共同操作呢?」於是 Global State 的概念就誕生了。

data.context-api---react-的-global-state#Conte:
Global State 的概念就像是住宅大廈的公共設施，它不單獨屬於任何一個人，也能夠被任何人取用。React 內建提供了一個實作 Global State 的方法，稱作 Context API。使用方法是使用
React.createContext(Context初始值);
現在，請創建src/context資料夾，並創立一個檔案ControlContext.js，在其中定義 OpenContext，其初始值為一個物件，裡面一次包好等等要用的openContext和setOpenContext。
import React from 'react';

export const OpenContext = React.createContext({
    openContext: true,
    setOpenContext: () => {},
});

data.provider---提供-context#Provider - 提供 Cont:
那麼 React 要如何把 Context 隔空提供給各個元件使用呢?答案是用一個叫做<Provider>的元件把所有需要這個 Context 的元件包起來。Provider 會內建於 Context 中，所以使用方式就是<xxxContext.Provider>現在，請在src/page/MenuPage引入 OpenContext，並用<OpenContext.Provider>把所有的東西包起來。
import React from 'react';

import MenuItem from '../component/MenuItem';
import Menu from '../component/Menu';
import { OpenContext } from '../context/ControlContext';

let menuItemWording = ['Like的發問', 'Like的回答', 'Like的文章', 'Like的留言'];

const MenuPage = () => {
    let menuItemArr = menuItemWording.map(wording => <MenuItem text={wording} />);

    return (
        <OpenContext.Provider>
            <Menu title={'Andy Chang的like'}>{menuItemArr}</Menu>
        </OpenContext.Provider>
    );
};

export default MenuPage;
但是現在 Context 裡面的資料只是普通變數而已，並不是 State。所以現在我們要在 MenuPage 中創造isOpen和setIsOpen。並把他丟給 OpenContext。綁給 OpenContext 的方式是利用 OpenContext.Provider 的一個 props -  value:
<OpenContext.Provider value={綁定值}></OpenContext.Provider>
實際加入程式碼中:
import React, { useState } from 'react';

import MenuItem from '../component/MenuItem';
import Menu from '../component/Menu';
import { OpenContext } from '../context/ControlContext';

let menuItemWording = ['Like的發問', 'Like的回答', 'Like的文章', 'Like的留言'];

const MenuPage = () => {
    const [isOpen, setIsOpen] = useState(true);

    let menuItemArr = menuItemWording.map(wording => <MenuItem text={wording} />);

    return (
        <OpenContext.Provider
            value={{
                openContext: isOpen,
                setOpenContext: setIsOpen,
            }}
        >
            <Menu title={'Andy Chang的like'}>{menuItemArr}</Menu>
        </OpenContext.Provider>
    );
};

export default MenuPage;

data.usecontext---在-function-component-中使用-co:
在 function component 中，取用 Context 的方式是先引入useContext和目標 context 後，透過
const data = useContext(xxxContext);
data 就會是剛剛存好的那個物件。現在請在 Menu 中，先把isOpen和setIsOpen拿掉，然後用useContext引入OpenContext。
import React, { useContext, useMemo } from 'react';
import { OpenContext } from '../context/ControlContext';
function Menu(props){
    const isOpenUtil = useContext(OpenContext);
這個 isOpenUtil 就會是剛剛存好的
isOpenUtil = {
    openContext: isOpen,
    setOpenContext: setIsOpen,
};
所以現在，我們先把 Menu 本來綁定isOpen的 button 改成用isOpenUtil裡面的東西看看能不能運作(先不管 ul 要不要顯示)
function Menu(props) {
    const isOpenUtil = useContext(OpenContext);
    return (
        <div style={menuContainerStyle}>
            <p style={menuTitleStyle}>{props.title}</p>
            <button
                style={menuBtnStyle}
                onClick={() => {
                    isOpenUtil.setOpenContext(!isOpenUtil.openContext);
                }}
            >
                {isOpenUtil.openContext ? '^' : 'V'}
            </button>
            <ul>{props.children}</ul>
        </div>
    );
}
恩，看起來能跟本來一樣的方法運作!
由於在<OpenContext.Provider></OpenContext.Provider>裡面的元件不管隔幾層、在哪裡都能取用OpenContext，我們就能用這種方式達成多層子父元件的溝通。現在，你應該有能力可以在 MenuItem 中實作剛剛前面講的功能了!

data:
在過去使用原生 JS 程式碼開發網頁時，常常遇到一個問題: 你會發現類似以下的程式碼不斷的在重複:
let menuContainer = document.createElement('div');
menuContainer.setAttribute('class', 'menu-container');

//藍色標題
let title = document.createElement('p');
title.setAttribute('class', 'menu-title');
title.textContent = 'Andy Chang的Like';
menuContainer.appendChild(title);
這樣的過程理論上也應該要被模組化包成函式比較好，於是 React 提供了一個類似的 API:
React.createElement('div', undefined, 'hello world');
除了第二個參數不知道為啥是undefined外，其他你應該都猜的出來是要做甚麼的。
實際上第一個參數是 component，第二個參數是 props，第三個參數是 children。現在不知道這些是啥沒關係，我們後面會提到
當然，React 不只是包了「創造一般元素的功能」進去這個 API 裡面，有興趣的可以去看看 React 的 source code。然而這樣還是不夠直覺。於是就產生了「讓 HTML 可以直接寫在 Javascript 的語法」 - JSX。

data.1-html-語法可以當作參數變數值傳遞#1. HTML 語法可以當作參數、變數:
例如，下方是合法的語法，會跟前一篇的 Hello world 一樣:
import React from 'react';
import { createRoot } from 'react-dom/client';

const menuFactory = () => {
    return <div>hello world!</div>;
};

const root = createRoot(document.getElementById('root'));
root.render(menuFactory());

data.2-傳遞-html-時只能傳遞一個標籤元素#2. 傳遞 HTML 時，只能傳遞一:
意思是下方這樣是錯誤的:
import React from 'react';
import { createRoot } from 'react-dom/client';

const root = createRoot(document.getElementById('root'));
root.render(<div>hello world!</div><button>我是按鍵</button>);
那如果我們想要傳遞多個元素怎麼辦?這個時候就要用一個 container 把元素包起來:
import React from 'react';
import ReactDOM from 'react-dom';

root.render(
    <div>
        <div>hello world!</div>
        <button>我是按鍵</button>
    </div>
);
但是這樣很容易多出一堆沒有用的 container。為了解決這個問題，React 提供了一個叫 Fragment 的元件。
import React, { Fragment } from 'react';
import { createRoot } from 'react-dom/client';

const root = createRoot(document.getElementById('root'));
root.render(
    <Fragment>
        <div>hello world!</div>
        <button>我是按鍵</button>
    </Fragment>
);
實際渲染到畫面上時，React 會自己把 Fragment 去除掉
另外如果嫌 Fragment 這個單字太長，React 也有提供Fragment 簡寫的語法:<></>
import React from 'react';
import { createRoot } from 'react-dom/client';

const root = createRoot(document.getElementById('root'));
root.render(
    <>
        <div>hello world!</div>
        <button>我是按鍵</button>
    </>
);
效果和剛剛一模一樣。

data.3-可以在-html-標籤中利用寫-javascript-表示式#3. 可以在:
以下面這個範例而言 :
import React from 'react';
import { createRoot } from 'react-dom/client';

const root = createRoot(document.getElementById('root'));
root.render(<div> {1 + 1} </div>);
執行結果是:
請注意如果要在{}中使用字串，就必須要使用"文字"或是'文字'，因為{}中就等於是 Javascript 語法了。相反的像true或false這種布林值就不能加上引號。

data.4-class屬性變成classname#4. 「class」屬性變成「clas:
//這是正確的寫法
root.render(
    <ul className="menu">
        <li className="menu-item">Like的發問</li>
    </ul>
);

//這是錯誤的寫法
root.render(
    <ul class="menu">
        <li class="menu-item">Like的發問</li>
    </ul>
);

const menuItemStyle = {
    marginBottom: '7px',
    paddingLeft: '26px',
    listStyle: 'none',
};

root.render(
    <ul className="menu">
        <li className="menu-item" style={menuItemStyle}>
            Like的發問
        </li>
    </ul>
);
需要特別注意的是直接在標籤中給 style 值的寫法:
root.render(
    <ul className="menu">
        <li
            className="menu-item"
            style={{ marginBottom: '7px', paddingLeft: '26px', listStyle: 'none' }}
        >
            Like的發問
        </li>
    </ul>
);
這裡之所以會有兩層大括號，是因為外面那層括號代表 style 要被賦予的值會是 javascript 語法，裡面的括號則表示物件型態。

data.6-元素-array-會被自動展開#6. 元素 Array 會被自動展開:
在下面的程式中，menuItemWording 是一個 array，React 就自動展開它裡面的元素並顯示。
import React from 'react';
import { createRoot } from 'react-dom/client';

const root = createRoot(document.getElementById('root'));

let menuItemWording = ['Like的發問', 'Like的回答', 'Like的文章', 'Like的留言'];
let menuItemArr = menuItemWording.map(wording => <li className="menu-item"> {wording}</li>);

root.render(<ul className="menu">{menuItemArr}</ul>);

data.7-jsx-的-js-表示式中可以用布林值比較來決定是否顯示元素#7. JSX:
在 Javascript 中有個特別的布林值比較語法。像是以下 code 代表如果condition為 true 時，回傳後面的 1
const condition = true;
const data = condition && 1;

console.log(data);
// 印出 1
我們可以將這個語法利用在 JSX 中，讓程式碼更簡潔。例如在以下程式碼中，你會發現按鍵並沒有被顯示
root.render(
    <ul className="menu">{false && <button>我是按鍵</button>}</ul>
);
換成這個就會顯示了
root.render(
    <ul className="menu">{true && <button>我是按鍵</button>}</ul>
);
也就是剛剛的程式碼其實等於
const menuItemFactory = () => {
    if (true) return <button>我是按鍵</button>;
};

root.render(<ul className="menu">{menuItemFactory()}</ul>);

data.8-所有原生的屬性名稱改為駝峰法命名#8. 所有原生的屬性名稱改為駝峰法命名:
例如，onclick 變成了 onClick。
const handleClick = event => {
    console.log(event.target.value);
};

root.render(
    <ul className="menu">
        <button value={87} onClick={handleClick}>
            我是按鍵
        </button>
    </ul>
);
有關其他輸入元素的控制方法，我們會在後面的章節提到。

data.react-17-之後#React 17 之後:
使用 JSX，再讓 babel 轉成React.createElement的做法在開發上雖然比以前方便很多，但也遇到了兩個問題:
為了要讓 Babel 知道要轉成React.createElement，每次在 React 元件的 JS 檔中都要import React from 'react'。
有一些改善效能、簡化的語法會因為React.createElement而不能使用。
為了解決這兩個問題，在 2020 年推出的 React 17 中，讓 babel 能夠在編譯時，只要遇到 JSX 就會知道要轉成一個新的函式 - jsx()。簡單來說，以後我們就不用在開頭一直import React from 'react'了!
jsx('h1', { children: 'Hello world' });
在目前(2024/02)的 React 中，預設還是用原本的編譯方式。如果你現在就想體驗這個功能，要對打包工具新增一些設定，詳情可以參考React 官網。
// If you are using @babel/preset-react
{
    "presets": [
        // 把@babel/preset-react改成下面這樣
        ["@babel/preset-react", { "runtime": "automatic" }]
    ]
}

data:
很多時候，我們的 state 必須要透過 HTTP Request 從後端取得。然而發送 Request 常用的 fetch 或是 axios 是非同步的。雖然我們可以透過以下方式把資料送進去 Redux:
fetch('URL', {
    method: 'GET',
})
    .then(res => res.json())
    .then(data => {
        dispatch({ type: 'TYPE', payload: { data } });
    })
    .catch(e => {
        /*發生錯誤時要做的事情*/
    });
但最理想的狀況還是讓這個 fetch 的過程被模組、抽象化，也就是不應該還要讓 UI 繪製程式還要自己去 call fectch API。我們希望 UI 繪製程式只需要呼叫一個函式，從 fetch 到更新 Redux 的這串過程都會完成。
不論是在 Flux，還是傳統的 MVC、MVP、MVVM 觀念下，都希望把資料處理的程式抽離 UI 繪製的程式，而不是讓兩者混雜在一起
講白一點，我們的流程本來是:
操作者呼叫 dispatch
Redux 判斷 action
Redux 根據 action 對 state 做出對應修改
現在我們希望流程改成這樣:
操作者呼叫 dispatch
一個遇到非同步事件，就會等到非同步事件結束才再次呼叫 dispatch、傳遞 action 的模組程式
Redux 判斷 action
Redux 根據 action 對 state 做出對應修改
一般會把 2 這種在本來行為之間(1 和 3)的加工過程稱為 middleware(中介層)。

data.redux-middleware-與-redux-thunk-的使用#Redux:
接下來我們會實際操作一次 Redux-Thunk，試著把 MenuItem 的資料改成從後端取得。資料會用我放在自己 github 的台灣的縣市列表 JSON 檔。
{
    "cityList":[
        "臺北市",
        "基隆市",
        "新北市",
        (略......)
    ]
}

data.2-建立-srcmodelactionjs#2. 建立 src/model/ac:
一般會在這裡以變數統一管理 action 字串。不過這裡我們先拿來放等等要定義的 fetch
在 src/model/action.js 中，定義一個函式，把 item 改成 fetch 函式得到的資料。Redux-Thunk 會把 dispatch 函式當成函式的參數傳入。我們則要在非同步事件結束後再次呼叫 dispatch，給予對應的 action 和 payload。因為現在我們的 reducer 還沒有這種一次修改所有資料的 action，我們先加一個SET_ITEM，等等再加回 reducer 中。
src/model/action.js
export const fetchCityItem = () => {
    return dispatch => {
        fetch('https://raw.githubusercontent.com/JiaAnTW/mask/master/dist.json', {
            method: 'GET',
        })
            .then(res => res.json())
            .then(data => {
                dispatch({
                    type: 'SET_ITEM',
                    payload: { itemNewArr: data['cityList'] },
                });
            })
            .catch(e => {
                console.log(e);
            });
    };
};

data.3-加入-redux-thunk-到-redux-中#3. 加入 Redux-T:
Redux 提供了applyMiddleware這個函式來讓我們安裝 middleware 到 Redux 中。用法是將applyMiddleware(中介層1,中介層2,...)放在 createStore 的第二個參數中。現在，請引入 Redux-Thunk 的thunk和 Redux 的applyMiddleware，並加入我們的 store 中:
src/model/store.js
import { createStore, applyMiddleware } from 'redux';
import { itemReducer } from './reducer.js';
import thunk from 'redux-thunk';

const itemStore = createStore(itemReducer, applyMiddleware(thunk));

export { itemStore };
這樣使用 Redux-thunk 的架構就完成了。

data.4-補回-reducer-處理-set_item-的-case#4. 補回 re:
src/model/reducer.js
const initState = {
    menuItemData: ['Like的發問', 'Like的回答', 'Like的文章', 'Like的留言'],
};

const itemReducer = (state = initState, action) => {
    switch (action.type) {
        case 'ADD_ITEM': {
            const menuItemCopy = state.menuItemData.slice();
            return { menuItemData: [action.payload.itemNew].concat(menuItemCopy) };
        }
        case 'SET_ITEM': {
            return { menuItemData: action.payload.itemNewArr };
        }
        case 'CLEAN_ITEM': {
            return { menuItemData: [] };
        }
        default:
            return state;
    }
};

export { itemReducer };

data.5-在需要的地方以-dispatch-呼叫-fetchcityitem#5. 在:
觸發 Redux-Thunk 的方式，是在需要的地方呼叫
dispatch(剛剛定義的非同步函式());
也就是你可以在 src/page/MenuPage 新增一個按鈕:
<button
    onClick={() => {
        dispatch(fetchCityItem());
    }}
>
    抓取並修改menuItem
</button>
按下去之後，Redux 就會根據我們剛剛定義的內容，先執行發送 Http Request，等資料回來，才執行 dispatch，把 action 和剛剛放入 payload 的縣市資料丟到 reducer 去更新。
src/page/MenuPage.js
import React, { useState, useReducer, useMemo, useEffect } from 'react';
import useMouseY from '../util/useMouseY';

import MenuItem from '../component/MenuItem';
import Menu from '../component/Menu';
import { OpenContext } from '../context/ControlContext';

import { useSelector, useDispatch } from 'react-redux';
import { fetchCityItem } from '../model/action';

const reducer = function (state, action) {
    switch (action.type) {
        case 'SWITCH':
            return !state;
        default:
            throw new Error('Unknown action');
    }
};

const MenuPage = () => {
    const [isOpen, isOpenDispatch] = useReducer(reducer, true);

    const menuItemData = useSelector(state => state.menuItemData);
    const dispatch = useDispatch();

    let menuItemArr = useMemo(
        () => menuItemData.map(wording => <MenuItem text={wording} key={wording} />),
        [menuItemData]
    );

    return (
        <OpenContext.Provider
            value={{
                openContext: isOpen,
                setOpenContext: isOpenDispatch,
            }}
        >
            <Menu title={'Andy Chang的like'}>{menuItemArr}</Menu>
            <button
                onClick={() => {
                    dispatch({
                        type: 'ADD_ITEM',
                        payload: { itemNew: '測試資料' },
                    });
                }}
            >
                更改第一個menuItem
            </button>
            <button
                onClick={() => {
                    dispatch(fetchCityItem());
                }}
            >
                抓取並修改menuItem
            </button>
        </OpenContext.Provider>
    );
};

export default MenuPage;

data.part1---認識-react-batching#Part.1 - 認識 Re:
首先，我們先假設 setState 絕對會是同步的(呼叫 setState 後 state 會馬上被改變)。在 React 中，我們很常都會透過 setState 去更新 state 和 props，藉此觸發 React 的更新機制(reconciliation)，比較 Virtual DOM 後，再去渲染畫面。然而 React 開發者在處理 setState 和判斷元件更新的關係時，一些效能問題出現了。我們來看看這個例子:下方程式碼中，Parent 引入了 Child。當 Child 被點擊時，由於event bubbling，其父層 Parent 中的 div 也會觸發onClick事件。
import { Component } from 'react';

class Child extends Component {
    constructor(props) {
        super(props);
        this.state = { count: 0 };
    }
    render() {
        return (
            <button onClick={() => this.setState({ count: this.state.count + 1 })}>
                Child clicked {this.state.count} times
            </button>
        );
    }
}

export default class Parent extends Component {
    constructor(props) {
        super(props);
        this.state = { count: 0 };
    }
    render() {
        return (
            <div onClick={() => this.setState({ count: this.state.count + 1 })}>
                Parent clicked {this.state.count} times
                <Child />
            </div>
        );
    }
}
直覺上來說，假設 setState 當下 state 就會被改變，我們預期的更新流程應該如下:
點擊行為一路向下補獲至 target(Child 的 button)
呼叫綁定在 Child 的 button 的 onClick function，觸發 setState
setState 導致 Child 的 state 被改變
Child 元件 re-render
onClick 事件透過 event bubble 冒泡回 Parent 的 div
呼叫綁定在 Parent 的 div 的 onClick function，觸發 setState
setState 導致 Parent 的 state 被改變
Parent 元件 re-render
由於 Child 是 Parent 的子元素，當 Parent 元件 re-render 時，Child 元件也要 re-render
觀察上述流程，我們會發現階段 4 產生的 re-render 是不必要的，因為在最後階段時 Child 又再 re-render 了一次。

data.註-什麼是-syntheticevent合成事件#註: 什麼是 Syntheti:
在 React 中，我們幾乎都會透過以 JSX 或是 React.createElement 呈現的 html element 上的 onClick、onChange 這些屬性進行事件處理、讓使用者的行為觸發呼叫 setState 函式、更新元件。而這些屬性和原生利用addEventListener、onclick做事件處理不同的地方在，React 針對自己的需求，在事件發生、呼叫 handler 到更新元件的過程中，多進行了某些加工。一個很明顯的例子是在使用ReactDOM.createPortal時，雖然實際渲染在 DOM 上的元素和原本 JSX 中的巢狀結構不再有父子關係，但 React 仍然會將event bubbling實作回 JSX 中引入其引入的父層元素中。這種在 React 中的事件處理稱為 SyntheticEvent(合成事件)。
import { createPortal } from 'react-dom';

function Child() {
    return createPortal(<button>ChildReact</button>, document.getElementById('portal-react'));
}

export default function Parent() {
    return (
        <div onClick={() => console.log('Parent被點擊了')}>
            <Child />
        </div>
    );
}
參考資料: https://zh-hant.reactjs.org/docs/events.html
batching 機制也同時避免了在同一次事件中大量呼叫 setState 所造成的資源浪費。例如，在下方的程式碼中，我們定義當 Child 中 button 被點擊時，在 Parent 中觸發三次 setState。觀察實際執行結果，會發現 React 並不會在呼叫一次 setState 後就馬上去根據 state 新的值去更新 DOM，而是根據所有 setState 依序執行後的 state 值去更新一次元件，所以「我被更新了」只會印出一次。
import { Component } from 'react';

class Child extends Component {
    constructor(props) {
        super(props);
    }
    render() {
        return (
            <div>
                <p>parent count is {this.props.count}</p>
                <button onClick={this.props.handleClick}>add Count</button>
            </div>
        );
    }
}

export default class Parent extends Component {
    constructor(props) {
        super(props);
        this.state = { count: 0 };
    }

    addCount = () => {
        let currentCount = this.state.count;
        for (let i = 0; i < 3; ++i) {
            currentCount++;
            this.setState({ count: currentCount });
        }
    };

    render() {
        console.log('我被更新了');
        return (
            <div>
                <Child handleClick={this.addCount} />
            </div>
        );
    }
}
參考資料: https://overreacted.io/react-as-a-ui-runtime/#batching

data.part2---確保-internal-consistency#Part.2 -:
雖然 batching 可能是個讓 setState 需要具有非同步特性的原因，然而其實只要不讓元件 re-render，立即更新 state 也可以做到 batching。我們試著來把剛剛的流程改這樣:
點擊行為一路向下補獲至 target(Child 的 button)
呼叫綁定在 Child 的 button 的 onClick function，觸發 setState
setState 導致 Child 的 state 被改變，並在某個地方記住此元件要更新。
onClick 事件透過 event bubble 冒泡回 Parent 的 div
呼叫綁定在 Parent 的 div 的 onClick function，觸發 setState
setState 導致 Parent 的 state 被改變，並在某個地方記住此元件要更新。
React 統一處理元件的更新
Parent 元件 re-render
Child 元件 re-render
看起來很完美，對吧?
然而這個時候，另一個問題又出現了: props。由於React 只有在父元件被 re-render 後，子元件才能知道其父元件賦予自己的 props 值，所以如果 props 也要隨著 state 的改變而同時被改變，那 state 改變後該元件就應該要馬上被 re-render，卻也導致沒辦法進行 batching 了。這會帶來相當大的資源浪費，所以，無論如何，props 的改變仍然是非同步的。那麼這會帶來什麼問題呢? 來看看以下這個範例，Child 負責顯示 Parent 的 count 數量，也能在 Child 連續兩次增加 Parent 中的 count 值:
import { Component } from 'react';

class Child extends Component {
    constructor(props) {
        super(props);
    }

    handleClick = () => {
        this.props.handleClick();
        console.log(this.props.count);
        this.props.handleClick();
        console.log(this.props.count);
    };

    render() {
        return (
            <div>
                <p>parent count is {this.props.count}</p>
                <button onClick={this.handleClick}>add Count 2 times</button>
            </div>
        );
    }
}

export default class Parent extends Component {
    constructor(props) {
        super(props);
        this.state = { count: 0 };
    }

    addCount = () => {
        this.setState({ count: count + 1 });
        console.log(this.state.count);
    };

    render() {
        console.log('更新了');
        return (
            <div>
                <Child props={this.count} handleClick={this.addCount} />
            </div>
        );
    }
}
依照我們剛剛制定state 更新是同步、props 更新是非同步的規則，當點擊 Child 中的 button 時，會產生的流程如下:
child 呼叫 this.handleClick
child 的 this.handleClick 第一次呼叫 Parent 綁定在 this.props.handleClick 上的 addCount
Parent 中的 addCount 呼叫 setState
Parent 印出 1(state.count 的值)
Child 印出 0(props.count 的值)
child 的 this.handleClick 第二次呼叫 Parent 綁定在 this.props.handleClick 上的 addCount
Parent 中的 addCount 呼叫 setState
Parent 印出 2(state.count 的值)
Child 印出 0(props.count 的值)
React 統一處理元件的更新
渲染 Parent
渲染 Child
注意到了嗎? 明明 Child 的 props.count 綁定了 Parent 的 state.count，但是在這個範例中，同一時間點得到的值會是不同的。由於這樣的不一致性容易造成開發者的困擾，所以，React 團隊決定 batching 機制下，藉由讓 setState 具有非同步特性，得以使被綁定的 state 和 props 之間能保持一致。到這邊，我們可以知道 React setState 之所以要是非同步的原因之一是 batching 和其延伸問題。另外還有一個原因是如果 setState 是非同步，React 團隊會更方便實現在 React 16 後推出的 React Fiber(非同步渲染機制)。和本文中提及一次處理所有元件的更新不同，雖然 batching 機制依然存在，但 React Fiber 將更新流程拆個多個片段，這樣「將原本一大包的更新拆成片段」的做法能夠讓瀏覽器在片段之間處理其他工作，解決了過去 React 在更新時偶而會發生的掉偵、卡頓問題。而如果 setState 是非同步的，在呼叫 setState 後，React 就能先透過一套演算法重新算出該更新任務的優先權，根據優先權再去決定該更新任務適合在哪個片段中執行。這部份細節自己暫時沒時間研究，就不多做介紹了。

data.在-react-17-以前的-class-component-中setstate:
藉由上一篇，我們可以知道為了透過實作 batching 進行效能優化，透過 React 機制所呼叫的 setState 都是非同步的，也就是當呼叫 setState 的當下 state 並不會馬上被改變。
這裡的 React 機制指的是包含生命週期函數、SyntheticEvent handler 等 (如: 以 React.createElement 或 JSX 呈現的 html element 上的 onClick、onChange)，詳細 SyntheticEvent 列表請參考官方文件。
所以，在下方的程式碼中，我們會發現在 handleClick 後的 console.log 印出的都是 state 修改前的值。(下方有 function component 版本)
export default class Apple extends Component {
    constructor(props) {
        super(props);
        this.state = { price: 0 };
    }

    handleClick = e => {
        // "e.target.value" is "this.state.price"
        this.setState({ price: Number(e.target.value) + 10 });
        console.log(`price is ${e.target.value}`);
    };

    render() {
        return (
            <div>
                <p> Apple is ${this.state.price}</p>
                <button id="price-control" value={this.state.price} onClick={this.handleClick}>
                    Add Apple's price
                </button>
            </div>
        );
    }
}
但是當我們不是使用 React 機制呼叫 setState 時，由於 batching 機制不存在，setState 就會是同步的。例如: 原生 addEvent listener 的 callback function、setTimoout 的 callback function.....等。在下方的範例中，我們會發現 setState 後馬上印出的值會是新 state 值。
export default class Apple extends Component {
    constructor(props) {
        super(props);
        this.state = { price: 0 };
    }

    handleClick = e => {
        // "e.target.value" is "this.state.price"
        this.setState({ price: Number(e.target.value) + 10 });
        console.log(`price is ${e.target.value}`);
    };

    componentDidMount() {
        document.getElementById('price-control').addEventListener('click', this.handleClick);
    }

    componentWillUnmount() {
        document.getElementById('price-control').removeEventListener('click', this.handleClick);
    }

    render() {
        return (
            <div>
                <p> Apple is ${this.state.price}</p>
                <button id="price-control" value={this.state.price}>
                    Add Apple's price
                </button>
            </div>
        );
    }
}

data.在在-react-17-以前的-function-component-中uses:
在 function component 中的 React hook 也是一樣的，透過 React 機制所呼叫的 setState 都是非同步，也就是當呼叫 setState 的當下 state 並不會馬上被改變。可以試著執行、比較下列程式碼的執行結果
非同步版本 - 透過 SyntheticEvent handler 觸發 handleClick
import { useState, useCallback } from 'react';

export default function Apple() {
    const [price, setPrice] = useState(0);

    // 透過JSX button的onClick觸發
    const handleClick = useCallback(e => {
        setPrice(Number(e.target.value) + 10);
        console.log(e.target.value);
    }, []);

    return (
        <div>
            <p> Apple is ${price}</p>
            <button id="price-control" value={price} onClick={handleClick}>
                Add Apple's price
            </button>
        </div>
    );
}
同步版本 - 透過原生 addEventListener callback function 觸發 handleClick，呼叫 setState 的當下 state 馬上會被改變
import { useState, useEffect, useCallback } from 'react';

export default function Apple() {
    const [price, setPrice] = useState(0);

    // 透過原生event listener觸發
    const handleClick = useCallback(e => {
        // "e.target.value" is "price"
        setPrice(Number(e.target.value) + 10);
        console.log(e.target.value);
    }, []);

    useEffect(() => {
        document.getElementById('price-control').addEventListener('click', handleClick);
        return () => {
            document.getElementById('price-control').removeEventListener('click', handleClick);
        };
    }, [handleClick]);

    return (
        <div>
            <p> Apple is ${price}</p>
            <button id="price-control" value={price}>
                Add Apple's price
            </button>
        </div>
    );
}

data.在-function-component-中-react-hook#在 func:
在 function component 中，如果我們想要拿到某個 state 被 setState 後的值，應該要為這個 state 多建立一個 useEffect，並把該 state 被改變後要做的事情(副作用)放在這個新 useEffect 內。下方是在建立元件後初始化 state 值，再檢視新的 state 值的作法:
import { useState, useEffect } from 'react';

export default function Apple() {
    const [price, setPrice] = useState(0);

    // ---正確的作法---
    useEffect(() => {
        setPrice(10);
    }, []);

    useEffect(() => {
        console.log(price);
    }, [price]);

    //----------------

    /* ---錯誤的方法一---
    useEffect(() => {
        setPrice(10);
        console.log(price);
    }, []);
    ----------------*/

    /* ---錯誤的方法二---
    useEffect(() => {
        setPrice(10);
        console.log(price);
    }, [price]);
    ----------------*/

    return (
        <div>
            <p> Apple is ${price}</p>
        </div>
    );
}
另外，useState 給予的 setState function 接收的參數原本其實也是函式，有的時候我們會想在設定某個 state 後，馬上根據同個 state 更新後的值去做下一次同個 state 的更新，此時我們可以改用「函式回傳值」的方式傳入新的值。React 會把更新後的 state 值傳入此 function 參數中，所以我們能在函式中用更新後的 state 值去做下一次同個 state 的更新。這樣的做法也能避免使用 useEffect 時需要思考是否會出現無限遞迴的情形。在下方的範例中，即使都是在建立元件後連續加 10 加 3 次，以非函式參數作法，price 會變成 10，且為了只在建立元件後執行，沒有把 price 放在 useEffect 的 dependence 參數中，嚴格模式下 React 會報錯:
import { useState } from 'react';

export default function Apple() {
    const [price, setPrice] = useState(0);

    useEffect(() => {
        setPrice(price + 10);
        setPrice(price + 10);
        setPrice(price + 10);
    }, []);

    return (
        <div>
            <p> Apple is ${price}</p>
        </div>
    );
}
而改傳入函式時，price 會在建立元件後變成 30。也因為運算的是 React 傳入函式的參數，而不是引入 state 本身，沒有違反嚴格模式的問題:
import { useState } from 'react';

export default function Apple() {
    const [price, setPrice] = useState(0);

    useEffect(() => {
        setPrice(prePrice => prePrice + 10);
        setPrice(prePrice => prePrice + 10);
        setPrice(prePrice => prePrice + 10);
    }, []);

    return (
        <div>
            <p> Apple is ${price}</p>
        </div>
    );
}
同時，使用 useReducer，藉由 reducer function 封裝處理 state 的邏輯也是可行的方法，也沒有違反嚴格模式的問題：
import { useReducer } from 'react';

function priceRedcuer(prevState, action) {
    switch (action.type) {
        case 'ADD':
            return prevState + 10;
        default:
            return prevState;
    }
}

export default function Apple() {
    const [price, priceDispatch] = useReducer(priceRedcuer, 0);

    useEffect(() => {
        priceDispatch({ type: 'ADD' });
        priceDispatch({ type: 'ADD' });
        priceDispatch({ type: 'ADD' });
    }, []);

    return (
        <div>
            <p> Apple is ${price}</p>
        </div>
    );
}

data.在-class-component-中setstate#在 class comp:
在 class component 中取得修改 state 後的值有兩種作法。第一種是利用 setState 函式本身提供的第二個參數，這個參數接收一個 function，React 會在 state 被更新後呼叫這個 callback function。我們就能在這個 function 參數中定義獲得新 state 後要做的事情。
export default class Apple extends Component {
    constructor(props) {
        super(props);
        this.state = { price: 0 };
    }

    componentDidMount() {
        this.setState({ price: 10 }, () => {
            console.log(this.state.price);
        });
    }

    render() {
        return (
            <div>
                <p> Apple is ${this.state.price}</p>
            </div>
        );
    }
}
第二種方法則是利用生命週期函數中的 componentDidUpdate。但需要特別注意的是，當該元件中任何 state 被 setState 設定時，componentDidUpdate 都會被重新呼叫。所以必須特別注意目前的邏輯是否有出現無限遞迴的可能。
export default class Apple extends Component {
    constructor(props) {
        super(props);
        this.state = { price: 0 };
    }

    componentDidMount() {
        this.setState({ price: 10 });
    }

    componentDidUpdate(prevProps, prevState, snapshot) {
        // 這個if是為了避免之後新增其他邏輯時出現非預期錯誤
        if (prevState.price !== this.state.price) {
            console.log(this.state.price);
        }
    }

    render() {
        return (
            <div>
                <p> Apple is ${this.state.price}</p>
            </div>
        );
    }
}
另外，setState 接收的第一個參數原本其實也是函式。如果想在某次設定 state 後，根據前次 state 更新後的值去做下一次的 state 更新，React 會把更新後的 state、props 值傳入此 function 參數中，所以我們能在此 function 用更新後的 state 值去做下一次的 state 更新。在下方的範例中，即使都是連續加 10 加 3 次，錯誤的作法下，price 會在建立元件後變成 10；正確的作法下，price 會在建立元件後變成 30。
export default class Apple extends Component {
    constructor(props) {
        super(props);
        this.state = { price: 0 };
    }

    componentDidMount() {
        // 錯誤的作法
        /*  
        this.setState({ price: this.state.price + 10 });
        this.setState({ price: this.state.price + 10 });
        this.setState({ price: this.state.price + 10 });
        */

        // 正確的作法
        for (let i = 0; i < 3; ++i) {
            this.setState((state, props) => {
                return { price: state.price + 10 };
            });
        }
    }

    render() {
        return (
            <div>
                <p> Apple is ${this.state.price}</p>
            </div>
        );
    }
}
參考資料:　https://zh-hant.reactjs.org/docs/react-component.html#setstate
